// Good code example: Proper use of Java API with parameterized queries to prevent SQL injection

import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
import java.sql.*;

public class GoodServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
        throws ServletException, IOException {

        // Proper input handling and parameterized query to prevent SQL injection
        String userInput = request.getParameter("username");

        String query = "SELECT * FROM users WHERE username = ?";

        try (Connection conn = DriverManager.getConnection("jdbc:mysql://localhost:3306/mydb", "user", "pass");
             PreparedStatement stmt = conn.prepareStatement(query)) {

            stmt.setString(1, userInput); // Safely bind the user input to the query

            try (ResultSet rs = stmt.executeQuery()) {
                while (rs.next()) {
                    String name = rs.getString("username");
                    response.getWriter().println("Welcome, " + name);
                }
            }
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}
